import json
import os
import pymysql


def get_db_connection():
    """Create and return a database connection using environment variables."""
    connection = pymysql.connect(
        host=os.environ.get('DB_HOST', 'localhost'),
        port=int(os.environ.get('DB_PORT', 3306)),
        user=os.environ.get('DB_USER', 'admin'),
        password=os.environ.get('DB_PASSWORD', ''),
        database=os.environ.get('DB_NAME', 'products_db'),
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=5,
        read_timeout=30,
        write_timeout=30
    )
    return connection


def build_search_query(params):
    """Dynamically build SQL query based on search parameters."""
    base_query = "SELECT * FROM products"
    conditions = []
    values = []

    # Text search on product name
    if params.get('name'):
        conditions.append("name LIKE %s")
        values.append(f"%{params['name']}%")

    # Text search on description
    if params.get('description'):
        conditions.append("description LIKE %s")
        values.append(f"%{params['description']}%")

    # Exact match on category
    if params.get('category'):
        conditions.append("category = %s")
        values.append(params['category'])

    # Exact match on brand
    if params.get('brand'):
        conditions.append("brand = %s")
        values.append(params['brand'])

    # Price range filtering
    if params.get('min_price'):
        try:
            min_price = float(params['min_price'])
            conditions.append("price >= %s")
            values.append(min_price)
        except (ValueError, TypeError):
            pass

    if params.get('max_price'):
        try:
            max_price = float(params['max_price'])
            conditions.append("price <= %s")
            values.append(max_price)
        except (ValueError, TypeError):
            pass

    # Exact match on SKU
    if params.get('sku'):
        conditions.append("sku = %s")
        values.append(params['sku'])

    # In-stock filter
    if params.get('in_stock') is not None:
        in_stock_val = params['in_stock']
        if isinstance(in_stock_val, str):
            in_stock_val = in_stock_val.lower() in ('true', '1', 'yes')
        if in_stock_val:
            conditions.append("stock_quantity > 0")
        else:
            conditions.append("stock_quantity = 0")

    # Minimum rating filter
    if params.get('min_rating'):
        try:
            min_rating = float(params['min_rating'])
            conditions.append("rating >= %s")
            values.append(min_rating)
        except (ValueError, TypeError):
            pass

    # Tags search (comma-separated)
    if params.get('tags'):
        tag_list = [tag.strip() for tag in params['tags'].split(',') if tag.strip()]
        if tag_list:
            tag_conditions = []
            for tag in tag_list:
                tag_conditions.append("tags LIKE %s")
                values.append(f"%{tag}%")
            conditions.append(f"({' OR '.join(tag_conditions)})")

    # Product ID filter
    if params.get('product_id'):
        try:
            product_id = int(params['product_id'])
            conditions.append("id = %s")
            values.append(product_id)
        except (ValueError, TypeError):
            pass

    # Date range filtering (created_at)
    if params.get('created_after'):
        conditions.append("created_at >= %s")
        values.append(params['created_after'])

    if params.get('created_before'):
        conditions.append("created_at <= %s")
        values.append(params['created_before'])

    # Active/inactive filter
    if params.get('is_active') is not None:
        is_active_val = params['is_active']
        if isinstance(is_active_val, str):
            is_active_val = is_active_val.lower() in ('true', '1', 'yes')
        conditions.append("is_active = %s")
        values.append(1 if is_active_val else 0)

    # Build WHERE clause
    if conditions:
        base_query += " WHERE " + " AND ".join(conditions)

    # Sorting
    allowed_sort_fields = {
        'name', 'price', 'created_at', 'rating', 'stock_quantity', 'category', 'brand'
    }
    sort_by = params.get('sort_by', 'created_at')
    if sort_by not in allowed_sort_fields:
        sort_by = 'created_at'

    sort_order = params.get('sort_order', 'DESC').upper()
    if sort_order not in ('ASC', 'DESC'):
        sort_order = 'DESC'

    base_query += f" ORDER BY {sort_by} {sort_order}"

    # Pagination
    try:
        limit = int(params.get('limit', 20))
        limit = min(max(limit, 1), 100)  # Clamp between 1 and 100
    except (ValueError, TypeError):
        limit = 20

    try:
        offset = int(params.get('offset', 0))
        offset = max(offset, 0)
    except (ValueError, TypeError):
        offset = 0

    base_query += " LIMIT %s OFFSET %s"
    values.append(limit)
    values.append(offset)

    return base_query, values, limit, offset


