def serialize_product(product):
    """Serialize product data for JSON response, handling special types."""
    serialized = {}
    for key, value in product.items():
        if hasattr(value, 'isoformat'):
            serialized[key] = value.isoformat()
        elif isinstance(value, bytes):
            serialized[key] = value.decode('utf-8')
        elif isinstance(value, (int, float, str, bool, type(None))):
            serialized[key] = value
        else:
            serialized[key] = str(value)
    return serialized


def create_response(status_code, body):
    """Create a standardized API Gateway response."""
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type,Authorization',
            'Access-Control-Allow-Methods': 'GET,POST,OPTIONS'
        },
        'body': json.dumps(body, default=str)
    }


def lambda_handler(event, context):
    """
    Main Lambda handler for product search API.

    Accepts search parameters via:
    - Query string parameters (GET requests)
    - Request body (POST requests)

    Supported parameters:
    - name: Product name (partial match)
    - description: Product description (partial match)
    - category: Exact category match
    - brand: Exact brand match
    - min_price: Minimum price filter
    - max_price: Maximum price filter
    - sku: Exact SKU match
    - in_stock: Boolean filter for stock availability
    - min_rating: Minimum rating filter
    - tags: Comma-separated tags (OR matching)
    - product_id: Exact product ID
    - created_after: Date filter (products created after)
    - created_before: Date filter (products created before)
    - is_active: Boolean filter for active products
    - sort_by: Field to sort by (name, price, created_at, rating, stock_quantity, category, brand)
    - sort_order: ASC or DESC
    - limit: Number of results (1-100, default 20)
    - offset: Pagination offset (default 0)
    """
    connection = None

    try:
        # Handle OPTIONS preflight request
        http_method = event.get('httpMethod', event.get('requestContext', {}).get('http', {}).get('method', 'GET'))
        if http_method == 'OPTIONS':
            return create_response(200, {'message': 'OK'})

        # Extract search parameters from event
        params = {}

        # From query string parameters
        query_params = event.get('queryStringParameters') or {}
        params.update(query_params)

        # From multi-value query string parameters
        multi_value_params = event.get('multiValueQueryStringParameters') or {}
        for key, values in multi_value_params.items():
            if key not in params and values:
                params[key] = values[0]

        # From request body (for POST requests)
        if event.get('body'):
            try:
                body = event['body']
                if isinstance(body, str):
                    body_params = json.loads(body)
                else:
                    body_params = body
                if isinstance(body_params, dict):
                    params.update(body_params)
            except (json.JSONDecodeError, TypeError):
                return create_response(400, {
                    'error': 'Invalid JSON in request body',
                    'message': 'The request body must be valid JSON'
                })

        # From path parameters
        path_params = event.get('pathParameters') or {}
        if path_params.get('product_id'):
            params['product_id'] = path_params['product_id']

        # Build and execute search query
        query, values, limit, offset = build_search_query(params)

        connection = get_db_connection()

        with connection.cursor() as cursor:
            # Get total count for pagination
            total_count = get_total_count(cursor, params)

            # Execute main search query
            cursor.execute(query, values)
            results = cursor.fetchall()

        # Serialize results
        products = [serialize_product(product) for product in results]

        # Build pagination metadata
        total_pages = (total_count + limit - 1) // limit if limit > 0 else 0
        current_page = (offset // limit) + 1 if limit > 0 else 1

        response_body = {
            'success': True,
            'data': {
                'products': products,
                'pagination': {
                    'total_count': total_count,
                    'total_pages': total_pages,
                    'current_page': current_page,
                    'limit': limit,
                    'offset': offset,
                    'has_next': (offset + limit) < total_count,
                    'has_previous': offset > 0
                }
            },
            'search_params': {k: v for k, v in params.items() if k not in ('limit', 'offset')}
        }

        return create_response(200, response_body)

    except pymysql.MySQLError as e:
        error_code = e.args[0] if e.args else 'Unknown'
        error_message = e.args[1] if len(e.args) > 1 else str(e)
        print(f"Database error [{error_code}]: {error_message}")

        return create_response(503, {
            'success': False,
            'error': 'Database error',
            'message': 'Unable to process your search request. Please try again later.'
        })

    except Exception as e:
        print(f"Unexpected error: {type(e).__name__}: {str(e)}")

        return create_response(500, {
            'success': False,
            'error': 'Internal server error',
            'message': 'An unexpected error occurred while processing your request.'
        })

    finally:
        if connection:
            try:
                connection.close()
            except Exception:
                pass